// ======================================================
// n8n Code Node - Normalize NextConvers Lead Payload
// Mode: Run Once for All Items
// Input: Webhook item with json.body
// Output: one normalized item per input item
// ======================================================

function cleanText(value) {
  if (value === null || value === undefined) return '';
  if (Array.isArray(value)) {
    value = value.map(v => cleanText(v)).filter(Boolean).join(', ');
  }
  return String(value)
    .replace(/\r?\n|\r/g, ' ')
    .replace(/\t/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function toNumber(value, fallback = 0) {
  if (value === null || value === undefined || value === '') return fallback;
  const num = Number(String(value).replace(/[^\d.-]/g, ''));
  return Number.isFinite(num) ? num : fallback;
}

function safeJsonParse(value) {
  if (!value) return {};
  if (typeof value === 'object') return value;
  try {
    return JSON.parse(value);
  } catch (_e) {
    return {};
  }
}

function getFirstName(fullName, fallback = '') {
  const name = cleanText(fullName);
  if (!name) return fallback;
  return name.split(' ')[0] || fallback;
}

function getLastName(fullName) {
  const name = cleanText(fullName);
  const parts = name.split(' ').filter(Boolean);
  if (parts.length <= 1) return '';
  return parts.slice(1).join(' ');
}

function normalizeLinkedinProfileUrl(url, publicIdentifier, profileId) {
  const cleanUrl = cleanText(url);
  if (cleanUrl.includes('/in/')) {
    return cleanUrl.split('?')[0].replace(/\/$/, '');
  }
  if (publicIdentifier) {
    return `https://www.linkedin.com/in/${publicIdentifier}`;
  }
  if (profileId) {
    return `https://www.linkedin.com/in/${profileId}`;
  }
  return cleanUrl;
}

function extractSkills(body, profileJson) {
  const skills = [];
  Object.keys(body || {}).forEach(key => {
    if (/^skills_\d+$/.test(key) && body[key]) {
      skills.push(cleanText(body[key]));
    }
  });
  if (Array.isArray(profileJson.topSkills)) {
    profileJson.topSkills.forEach(skill => {
      if (skill) skills.push(cleanText(skill));
    });
  }
  if (Array.isArray(profileJson.skills)) {
    profileJson.skills.forEach(skill => {
      if (skill?.name) skills.push(cleanText(skill.name));
    });
  }
  const parsedSkills = safeJsonParse(body.skills);
  if (Array.isArray(parsedSkills)) {
    parsedSkills.forEach(skill => {
      if (typeof skill === 'string') skills.push(cleanText(skill));
      else if (skill?.name) skills.push(cleanText(skill.name));
    });
  }
  return [...new Set(skills.filter(Boolean))];
}

function getCurrentPosition(profileJson, body) {
  if (Array.isArray(profileJson.currentPosition) && profileJson.currentPosition.length > 0) {
    return profileJson.currentPosition[0];
  }
  if (Array.isArray(profileJson.experience) && profileJson.experience.length > 0) {
    return profileJson.experience[0];
  }
  return {
    position: cleanText(body.headline),
    companyName: cleanText(body.company_name),
    companyLinkedinUrl: cleanText(body.company_linkedin_url),
    description: cleanText(body.current_company_description),
  };
}

function normalizeReactedPosts(posts) {
  const parsed = Array.isArray(posts) ? posts : safeJsonParse(posts);
  if (!Array.isArray(parsed)) return [];
  return parsed.map(post => ({
    id: toNumber(post.id),
    url: cleanText(post.url),
    react_type: cleanText(post.react_type).toUpperCase(),
    reacted_at: cleanText(post.reacted_at),
  }));
}

return items.map(item => {
  let raw = item.json || {};
  try {
    const webhookItem = $('Webhook').first();
    if (webhookItem && webhookItem.json) {
      raw = webhookItem.json;
    }
  } catch (_e) {
    // Webhook node not in execution path; use current item
  }
  const body = raw.body || raw;

  const profileJson = safeJsonParse(body.reduced_profile_json_content);
  const currentPosition = getCurrentPosition(profileJson, body);

  const publicIdentifier = cleanText(profileJson.publicIdentifier || body.public_identifier);
  const profileId = cleanText(body.profile_id || profileJson.id);
  const fullName = cleanText(body.name || `${profileJson.firstName || ''} ${profileJson.lastName || ''}`);
  const firstName = cleanText(profileJson.firstName || body.first_name) || getFirstName(fullName);
  const lastName = cleanText(profileJson.lastName || body.last_name) || getLastName(fullName);

  const linkedinUrl = normalizeLinkedinProfileUrl(
    body.profile_url || body.linkedin_url || profileJson.linkedinUrl,
    publicIdentifier,
    profileId
  );

  const locationParsed = profileJson.location?.parsed || {};
  const locationText =
    cleanText(locationParsed.text) ||
    cleanText(profileJson.location?.linkedinText) ||
    cleanText(body.location);

  const companyName = cleanText(currentPosition.companyName || body.company_name);
  const companyLinkedinUrl = cleanText(currentPosition.companyLinkedinUrl || body.company_linkedin_url);

  const skills = extractSkills(body, profileJson);
  const topSkillsRaw = body.top_skills || profileJson.topSkills;
  const topSkillsParsed = Array.isArray(topSkillsRaw) ? topSkillsRaw : safeJsonParse(topSkillsRaw);
  const topSkills = Array.isArray(topSkillsParsed)
    ? topSkillsParsed.map(cleanText).filter(Boolean)
    : [];

  const reactedPosts = normalizeReactedPosts(body.reacted_posts);

  const normalized = {
    source_row_id: toNumber(body.id || body.source_row_id),
    profile_id: profileId,
    public_identifier: publicIdentifier,
    linkedin_url: linkedinUrl,
    profile_url: linkedinUrl,
    name: fullName,
    first_name: firstName,
    last_name: lastName,
    headline: cleanText(body.headline || profileJson.headline),
    country_code: cleanText(body.country_code || locationParsed.countryCode || profileJson.location?.countryCode).toUpperCase(),
    country: cleanText(body.country || locationParsed.country || locationParsed.countryFull),
    state: cleanText(body.state || locationParsed.state),
    city: cleanText(body.city || locationParsed.city),
    location: locationText,
    company_name: companyName,
    company_linkedin_url: companyLinkedinUrl,
    company_industry: cleanText(body.company_industry),
    current_position: cleanText(currentPosition.position || body.current_position),
    current_company_description: cleanText(
      currentPosition.description || body.current_company_description || body.positions_1_description
    ),
    summary: cleanText(body.summary || profileJson.about),
    quick_summary: cleanText(body.quick_summary || body.summary),
    connections_count: toNumber(body.connections_count || profileJson.connectionsCount),
    follower_count: toNumber(body.follower_count || profileJson.followerCount),
    skills_text: skills.join(', '),
    top_skills_text: topSkills.join(', '),
    react_type: cleanText(body.react_type).toUpperCase(),
    reacts_count: toNumber(body.reacts_count),
    reacted_posts_count: reactedPosts.length,
    post_url: cleanText(body.post_url),
    profile_score: toNumber(body.profile_score),
    profile_score_summary: cleanText(body.profile_score_summary),
    company_score: toNumber(body.company_score),
    company_score_summary: cleanText(body.company_score_Summary || body.company_score_summary),
    campaign_name: cleanText(body.campaign_name),
    account_id: cleanText(body.account_id),
    current_company_employee_count: toNumber(body.current_company_employeeCount || body.current_company_employee_count),
    current_company_headquarter_city: cleanText(body.current_company_headquarter_city),
    current_company_headquarter_country: cleanText(body.current_company_headquarter_country),
    current_company_headquarter_region: cleanText(body.current_company_headquarter_geographicArea || body.current_company_headquarter_region),
    email_enriched: cleanText(body.email_enriched || body.email),
    raw_payload: JSON.stringify(body),
  };

  return { json: normalized };
});

const lead = $('Normalize Lead').first().json;
const policyExact = $('Load Campaign Policy').first().json;
const policyDefault = $('Load Default Policy').first().json;
const suppressionsResp = $('Load Suppressions').first().json;
const idempotencyResp = $('Idempotency Lookup').first().json;
function getRecords(resp) {
  if (!resp) return [];
  if (Array.isArray(resp.list)) return resp.list;
  if (Array.isArray(resp.records)) return resp.records;
  if (Array.isArray(resp)) return resp;
  return [];
}
const exactRecords = getRecords(policyExact);
const defaultRecords = getRecords(policyDefault);
const policy = exactRecords[0] || defaultRecords[0] || null;
const suppressionRecords = getRecords(suppressionsResp);
const campaignName = lead.campaign_name || '';
const filteredSuppressions = suppressionRecords.filter(s => {
  if (s.active === false || s.active === 'false' || s.active === 0) return false;
  if (!s.campaign_name || s.campaign_name === '') return true;
  return s.campaign_name === campaignName;
});
const existingRecords = getRecords(idempotencyResp);
const existing = existingRecords[0] || null;
return [{ json: { lead, policy, suppressions: filteredSuppressions, existing_decision_id: existing ? existing.id : null } }];

// ======================================================
// n8n Code Node - Evaluate Hard Rules (config-driven)
// Mode: Run Once for All Items
// Input: lead, policy (parsed), suppressions
// Output: evaluation context object
// ======================================================

// --- lib/parse-config-array.js ---
function parseConfigArray(value) {
  if (value === null || value === undefined || value === '') return [];
  if (Array.isArray(value)) return value.map(v => String(v).trim()).filter(Boolean);
  const str = String(value).trim();
  if (!str) return [];
  if (str.startsWith('[')) {
    try {
      const parsed = JSON.parse(str);
      if (Array.isArray(parsed)) return parsed.map(v => String(v).trim()).filter(Boolean);
    } catch (_e) { /* fall through */ }
  }
  return str.split(/[,;\n]/).map(s => s.trim()).filter(Boolean);
}

// --- lib/text-match.js ---
function normalizeForMatch(text) {
  return String(text || '').toLowerCase().replace(/\s+/g, ' ').trim();
}

function containsAnyInFields(fields, patterns) {
  if (!patterns || !patterns.length) return false;
  const combined = fields.filter(Boolean).join(' ');
  const h = normalizeForMatch(combined);
  return patterns.some(p => h.includes(normalizeForMatch(p)));
}

function findMatchingPatterns(fields, patterns) {
  const combined = fields.filter(Boolean).join(' ');
  if (!combined || !patterns || !patterns.length) return [];
  const h = normalizeForMatch(combined);
  return patterns.filter(p => h.includes(normalizeForMatch(p)));
}

// --- lib/suppression-match.js ---
function normalizeLinkedinUrl(url) {
  const s = String(url || '').trim().toLowerCase();
  if (!s) return '';
  return s.split('?')[0].replace(/\/$/, '');
}

function normalizeName(name) {
  return String(name || '').toLowerCase().replace(/[^\w\s]/g, ' ').replace(/\s+/g, ' ').trim();
}

function extractDomain(value) {
  const s = String(value || '').trim().toLowerCase();
  if (!s) return '';
  try {
    const withProto = s.includes('://') ? s : `https://${s}`;
    return new URL(withProto).hostname.replace(/^www\./, '');
  } catch (_e) {
    const parts = s.split('@');
    if (parts.length === 2) return parts[1].split('/')[0].replace(/^www\./, '');
    return s.replace(/^www\./, '').split('/')[0];
  }
}

function getLeadFieldValue(lead, entityType) {
  switch (entityType) {
    case 'company_name': return lead.company_name || '';
    case 'company_domain': return extractDomain(lead.company_linkedin_url || lead.email_enriched || '');
    case 'linkedin_company_url': return lead.company_linkedin_url || '';
    case 'person_linkedin_url': return lead.linkedin_url || lead.profile_url || '';
    case 'profile_id': return lead.profile_id || '';
    case 'headline_keyword': return lead.headline || '';
    case 'title_keyword': return lead.current_position || lead.headline || '';
    case 'company_industry': return lead.company_industry || '';
    case 'company_type':
      return [lead.company_industry, lead.current_company_description, lead.company_name].filter(Boolean).join(' ');
    case 'email_domain': return extractDomain(lead.email_enriched || '');
    default: return '';
  }
}

function matchSuppression(lead, entity) {
  const entityType = entity.entity_type || '';
  const entityValue = entity.entity_value || '';
  const matchType = entity.match_type || 'exact';
  const leadValue = getLeadFieldValue(lead, entityType);
  if (!entityValue || !leadValue) return false;

  switch (matchType) {
    case 'exact':
      return normalizeForMatch(leadValue) === normalizeForMatch(entityValue);
    case 'contains':
      return normalizeForMatch(leadValue).includes(normalizeForMatch(entityValue));
    case 'domain': {
      const ld = extractDomain(leadValue);
      const ed = extractDomain(entityValue);
      return ld && ed && ld === ed;
    }
    case 'linkedin_url':
      return normalizeLinkedinUrl(leadValue) === normalizeLinkedinUrl(entityValue);
    case 'normalized_name':
      return normalizeName(leadValue) === normalizeName(entityValue);
    default:
      return normalizeForMatch(leadValue) === normalizeForMatch(entityValue);
  }
}

function evaluateSuppressions(lead, suppressions) {
  const matches = [];
  for (const entity of suppressions || []) {
    if (entity.active === false || entity.active === 'false' || entity.active === 0) continue;
    if (matchSuppression(lead, entity)) {
      matches.push({
        id: entity.id,
        entity_type: entity.entity_type,
        entity_value: entity.entity_value,
        match_type: entity.match_type,
        reason: entity.reason || '',
        severity: entity.severity || 'reject',
        campaign_name: entity.campaign_name || '',
      });
    }
  }
  return matches;
}

// --- Policy parsing ---
function parsePolicy(policy) {
  if (!policy || !policy.id) return null;
  return {
    ...policy,
    allowed_countries: parseConfigArray(policy.allowed_countries),
    excluded_countries: parseConfigArray(policy.excluded_countries),
    allowed_industries: parseConfigArray(policy.allowed_industries),
    excluded_industries: parseConfigArray(policy.excluded_industries),
    target_roles: parseConfigArray(policy.target_roles),
    review_roles: parseConfigArray(policy.review_roles),
    excluded_roles: parseConfigArray(policy.excluded_roles),
    target_departments: parseConfigArray(policy.target_departments),
    excluded_departments: parseConfigArray(policy.excluded_departments),
    target_company_types: parseConfigArray(policy.target_company_types),
    review_company_types: parseConfigArray(policy.review_company_types),
    excluded_company_types: parseConfigArray(policy.excluded_company_types),
    target_keywords: parseConfigArray(policy.target_keywords),
    review_keywords: parseConfigArray(policy.review_keywords),
    excluded_keywords: parseConfigArray(policy.excluded_keywords),
    min_profile_score: Number(policy.min_profile_score) || 0,
    min_company_score: Number(policy.min_company_score) || 0,
    min_company_size: Number(policy.min_company_size) || 0,
    max_company_size: Number(policy.max_company_size) || 0,
    ready_for_crm_profile_score: Number(policy.ready_for_crm_profile_score) || 4,
    ready_for_crm_company_score: Number(policy.ready_for_crm_company_score) || 3,
    auto_ready_threshold: Number(policy.auto_ready_threshold) || 1,
    review_threshold: Number(policy.review_threshold) || 1,
    review_if_profile_score_high_company_score_low:
      policy.review_if_profile_score_high_company_score_low === true ||
      policy.review_if_profile_score_high_company_score_low === 'true' ||
      policy.review_if_profile_score_high_company_score_low === 1,
    require_no_suppression_match:
      policy.require_no_suppression_match === true ||
      policy.require_no_suppression_match === 'true' ||
      policy.require_no_suppression_match === 1,
  };
}

function toBool(val) {
  return val === true || val === 'true' || val === 1 || val === '1';
}

function evaluateHardRules(lead, rawPolicy, suppressions) {
  const ctx = {
    suppression_matches: [],
    risk_flags: [],
    positive_signals: [],
    reject_reasons: [],
    review_reasons: [],
    hard_reject: false,
    suppression_reject: false,
    force_review: false,
    policy_found: false,
  };

  const policy = parsePolicy(rawPolicy);
  if (!policy) {
    ctx.force_review = true;
    ctx.review_reasons.push('No active policy found');
    return ctx;
  }
  ctx.policy_found = true;

  // Suppression check
  ctx.suppression_matches = evaluateSuppressions(lead, suppressions);
  const rejectMatches = ctx.suppression_matches.filter(m => m.severity === 'reject');
  const reviewMatches = ctx.suppression_matches.filter(m => m.severity === 'review');

  if (rejectMatches.length > 0) {
    ctx.suppression_reject = true;
    ctx.reject_reasons.push(`Suppression match: ${rejectMatches.map(m => m.reason || m.entity_value).join('; ')}`);
    return ctx;
  }

  for (const m of reviewMatches) {
    ctx.risk_flags.push(`Suppression review: ${m.reason || m.entity_value}`);
  }

  const roleFields = [lead.headline, lead.current_position];
  const companyFields = [lead.company_industry, lead.current_company_description, lead.company_name, lead.summary];

  // Score gates
  if (policy.min_profile_score > 0 && lead.profile_score < policy.min_profile_score) {
    ctx.hard_reject = true;
    ctx.reject_reasons.push(`Profile score ${lead.profile_score} below minimum ${policy.min_profile_score}`);
  }

  if (policy.min_company_score > 0 && lead.company_score < policy.min_company_score) {
    if (policy.review_if_profile_score_high_company_score_low &&
        lead.profile_score >= policy.ready_for_crm_profile_score) {
      ctx.review_reasons.push(`Company score ${lead.company_score} below minimum ${policy.min_company_score} but profile score is high`);
    } else {
      ctx.hard_reject = true;
      ctx.reject_reasons.push(`Company score ${lead.company_score} below minimum ${policy.min_company_score}`);
    }
  }

  if (policy.review_if_profile_score_high_company_score_low &&
      lead.profile_score >= policy.ready_for_crm_profile_score &&
      lead.company_score < policy.ready_for_crm_company_score) {
    ctx.review_reasons.push(`High profile score (${lead.profile_score}) with low company score (${lead.company_score})`);
  }

  // Company size
  if (policy.min_company_size > 0 && lead.current_company_employee_count > 0 &&
      lead.current_company_employee_count < policy.min_company_size) {
    ctx.hard_reject = true;
    ctx.reject_reasons.push(`Company size ${lead.current_company_employee_count} below minimum ${policy.min_company_size}`);
  }

  if (policy.max_company_size > 0 && lead.current_company_employee_count > policy.max_company_size) {
    ctx.review_reasons.push(`Company size ${lead.current_company_employee_count} above maximum ${policy.max_company_size}`);
  }

  // Geography
  const country = normalizeForMatch(lead.country_code || lead.country);
  if (policy.excluded_countries.length && policy.excluded_countries.some(c => normalizeForMatch(c) === country || normalizeForMatch(c) === normalizeForMatch(lead.country))) {
    ctx.hard_reject = true;
    ctx.reject_reasons.push(`Country ${lead.country || lead.country_code} is excluded`);
  }

  if (policy.allowed_countries.length) {
    const allowed = policy.allowed_countries.some(c => {
      const nc = normalizeForMatch(c);
      return nc === country || nc === normalizeForMatch(lead.country);
    });
    if (!allowed) {
      ctx.review_reasons.push(`Country ${lead.country || lead.country_code} not in allowed list`);
    }
  }

  // Industry
  if (policy.excluded_industries.length && containsAnyInFields([lead.company_industry], policy.excluded_industries)) {
    ctx.hard_reject = true;
    ctx.reject_reasons.push(`Industry ${lead.company_industry} is excluded`);
  }

  if (policy.allowed_industries.length && lead.company_industry &&
      !containsAnyInFields([lead.company_industry], policy.allowed_industries)) {
    ctx.review_reasons.push(`Industry ${lead.company_industry} not in allowed list`);
  }

  // Roles and keywords
  const excludedRoleHits = findMatchingPatterns(roleFields, policy.excluded_roles);
  if (excludedRoleHits.length) {
    ctx.hard_reject = true;
    ctx.reject_reasons.push(`Excluded role match: ${excludedRoleHits.join(', ')}`);
  }

  const excludedKeywordHits = findMatchingPatterns([...roleFields, ...companyFields], policy.excluded_keywords);
  if (excludedKeywordHits.length) {
    ctx.hard_reject = true;
    ctx.reject_reasons.push(`Excluded keyword match: ${excludedKeywordHits.join(', ')}`);
  }

  const reviewRoleHits = findMatchingPatterns(roleFields, policy.review_roles);
  if (reviewRoleHits.length) {
    ctx.review_reasons.push(`Review role match: ${reviewRoleHits.join(', ')}`);
  }

  const reviewKeywordHits = findMatchingPatterns([...roleFields, ...companyFields], policy.review_keywords);
  if (reviewKeywordHits.length) {
    ctx.review_reasons.push(`Review keyword match: ${reviewKeywordHits.join(', ')}`);
  }

  const targetRoleHits = findMatchingPatterns(roleFields, policy.target_roles);
  if (targetRoleHits.length) {
    ctx.positive_signals.push(`Target role match: ${targetRoleHits.join(', ')}`);
  }

  const targetKeywordHits = findMatchingPatterns([...roleFields, ...companyFields], policy.target_keywords);
  if (targetKeywordHits.length) {
    ctx.positive_signals.push(`Target keyword match: ${targetKeywordHits.join(', ')}`);
  }

  // Company types
  const excludedCompanyTypeHits = findMatchingPatterns(companyFields, policy.excluded_company_types);
  if (excludedCompanyTypeHits.length) {
    ctx.hard_reject = true;
    ctx.reject_reasons.push(`Excluded company type: ${excludedCompanyTypeHits.join(', ')}`);
  }

  const reviewCompanyTypeHits = findMatchingPatterns(companyFields, policy.review_company_types);
  if (reviewCompanyTypeHits.length) {
    ctx.review_reasons.push(`Review company type: ${reviewCompanyTypeHits.join(', ')}`);
  }

  const targetCompanyTypeHits = findMatchingPatterns(companyFields, policy.target_company_types);
  if (targetCompanyTypeHits.length) {
    ctx.positive_signals.push(`Target company type: ${targetCompanyTypeHits.join(', ')}`);
  }

  // Departments
  const excludedDeptHits = findMatchingPatterns(roleFields, policy.excluded_departments);
  if (excludedDeptHits.length) {
    ctx.hard_reject = true;
    ctx.reject_reasons.push(`Excluded department: ${excludedDeptHits.join(', ')}`);
  }

  const targetDeptHits = findMatchingPatterns(roleFields, policy.target_departments);
  if (targetDeptHits.length) {
    ctx.positive_signals.push(`Target department: ${targetDeptHits.join(', ')}`);
  }

  // Suppression requirement for CRM path
  if (toBool(policy.require_no_suppression_match) && ctx.suppression_matches.length > 0) {
    ctx.risk_flags.push('Suppression match present (require_no_suppression_match)');
  }

  return ctx;
}

// --- MAIN (n8n) ---
return items.map(item => {
  const data = item.json || {};
  const lead = data.lead || data;
  const policy = data.policy || null;
  const suppressions = data.suppressions || [];

  const evaluation = evaluateHardRules(lead, policy, suppressions);

  return {
    json: {
      lead,
      policy,
      suppressions,
      evaluation,
    },
  };
});

// ======================================================
// n8n Code Node - Build Decision Output
// Mode: Run Once for All Items
// Input: lead, policy, evaluation context
// Output: final decision + webhook response + NocoDB row
// ======================================================

function computeConfidence(lead, evaluation, status) {
  let score = 50;
  score += Math.min(lead.profile_score || 0, 5) * 5;
  score += Math.min(lead.company_score || 0, 5) * 3;
  score += (evaluation.positive_signals || []).length * 5;
  score -= (evaluation.risk_flags || []).length * 8;
  score -= (evaluation.review_reasons || []).length * 4;

  if (status === 'READY_FOR_CRM') score = Math.max(score, 75);
  if (status === 'REJECTED' || status === 'SUPPRESSED') score = Math.min(score, 30);
  if (status === 'READY_FOR_REVIEW') score = Math.min(Math.max(score, 40), 70);

  return Math.max(0, Math.min(100, Math.round(score)));
}

function buildDecision(lead, policy, evaluation) {
  const ev = evaluation || {};
  const parsedPolicy = policy || {};

  let qualification_status = 'READY_FOR_REVIEW';
  let reject_reason = '';
  let review_reason = '';
  let decision_reason = '';
  let crm_sync_status = 'review';

  const autoReadyThreshold = Number(parsedPolicy.auto_ready_threshold) || 1;
  const reviewThreshold = Number(parsedPolicy.review_threshold) || 1;
  const crmProfileScore = Number(parsedPolicy.ready_for_crm_profile_score) || 4;
  const crmCompanyScore = Number(parsedPolicy.ready_for_crm_company_score) || 3;

  const positiveCount = (ev.positive_signals || []).length;
  const riskCount = (ev.risk_flags || []).length;
  const hasReject = ev.hard_reject || ev.suppression_reject || (ev.reject_reasons || []).length > 0;

  if (ev.suppression_reject) {
    qualification_status = 'SUPPRESSED';
    reject_reason = (ev.reject_reasons || []).join('; ') || 'Suppression match';
    decision_reason = reject_reason;
    crm_sync_status = 'blocked';
  } else if (hasReject) {
    qualification_status = 'REJECTED';
    reject_reason = (ev.reject_reasons || []).join('; ');
    decision_reason = reject_reason;
    crm_sync_status = 'blocked';
  } else if (!ev.policy_found || ev.force_review) {
    qualification_status = 'READY_FOR_REVIEW';
    review_reason = (ev.review_reasons || []).join('; ') || 'No active policy found';
    decision_reason = review_reason;
    crm_sync_status = 'review';
  } else if (
    lead.profile_score >= crmProfileScore &&
    lead.company_score >= crmCompanyScore &&
    positiveCount >= autoReadyThreshold &&
    riskCount === 0 &&
    (ev.review_reasons || []).length === 0
  ) {
    qualification_status = 'READY_FOR_CRM';
    decision_reason = `Meets CRM thresholds (profile ${lead.profile_score}, company ${lead.company_score}) with ${positiveCount} positive signal(s)`;
    crm_sync_status = 'pending';
  } else if (
    (ev.review_reasons || []).length > 0 ||
    riskCount >= reviewThreshold ||
    positiveCount < autoReadyThreshold
  ) {
    qualification_status = 'READY_FOR_REVIEW';
    const parts = [];
    if ((ev.review_reasons || []).length) parts.push(...ev.review_reasons);
    if (riskCount >= reviewThreshold) parts.push(`${riskCount} risk flag(s)`);
    if (positiveCount < autoReadyThreshold) parts.push(`Insufficient positive signals (${positiveCount}/${autoReadyThreshold})`);
    review_reason = parts.join('; ');
    decision_reason = review_reason || 'Ambiguous — manual review recommended';
    crm_sync_status = 'review';
  } else {
    qualification_status = 'READY_FOR_REVIEW';
    review_reason = 'Did not meet auto-ready criteria';
    decision_reason = review_reason;
    crm_sync_status = 'review';
  }

  const qualification_confidence = computeConfidence(lead, ev, qualification_status);

  const webhook_response = {
    source_row_id: String(lead.source_row_id || ''),
    linkedin_url: lead.linkedin_url || '',
    campaign_name: lead.campaign_name || '',
    qualification_status,
    qualification_confidence,
    decision_reason,
    risk_flags: ev.risk_flags || [],
    positive_signals: ev.positive_signals || [],
    crm_sync_status,
  };

  const lead_decision_row = {
    account_id: lead.account_id || '',
    campaign_name: lead.campaign_name || '',
    product_name: parsedPolicy.product_name || '',
    motion_type: parsedPolicy.motion_type || '',
    source_row_id: lead.source_row_id || null,
    profile_id: lead.profile_id || '',
    public_identifier: lead.public_identifier || '',
    linkedin_url: lead.linkedin_url || '',
    profile_url: lead.profile_url || '',
    name: lead.name || '',
    first_name: lead.first_name || '',
    last_name: lead.last_name || '',
    headline: lead.headline || '',
    country_code: lead.country_code || '',
    country: lead.country || '',
    state: lead.state || '',
    city: lead.city || '',
    location: lead.location || '',
    company_name: lead.company_name || '',
    company_linkedin_url: lead.company_linkedin_url || '',
    company_industry: lead.company_industry || '',
    current_position: lead.current_position || '',
    current_company_description: lead.current_company_description || '',
    summary: lead.summary || '',
    quick_summary: lead.quick_summary || '',
    connections_count: lead.connections_count || null,
    follower_count: lead.follower_count || null,
    skills_text: lead.skills_text || '',
    top_skills_text: lead.top_skills_text || '',
    react_type: lead.react_type || '',
    reacts_count: lead.reacts_count || null,
    reacted_posts_count: lead.reacted_posts_count || null,
    post_url: lead.post_url || '',
    profile_score: lead.profile_score || null,
    profile_score_summary: lead.profile_score_summary || '',
    company_score: lead.company_score || null,
    company_score_summary: lead.company_score_summary || '',
    current_company_employee_count: lead.current_company_employee_count || null,
    current_company_headquarter_city: lead.current_company_headquarter_city || '',
    current_company_headquarter_country: lead.current_company_headquarter_country || '',
    current_company_headquarter_region: lead.current_company_headquarter_region || '',
    email_enriched: lead.email_enriched || '',
    qualification_status,
    qualification_confidence,
    decision_reason,
    reject_reason,
    review_reason,
    suppression_matches: JSON.stringify(ev.suppression_matches || []),
    risk_flags: JSON.stringify(ev.risk_flags || []),
    positive_signals: JSON.stringify(ev.positive_signals || []),
    crm_sync_status,
    raw_payload: lead.raw_payload || '',
  };

  return {
    ...lead_decision_row,
    webhook_response,
    evaluation: ev,
  };
}

